    23→TEST(ArcReplacerTest, DISABLED_SampleTest) {
    24→  // for the sake of simplicity
    25→  // we use (a, fb) to notate page a on frame b,
    26→  // (a, _) to mark ghost page with page id a
    27→  // p(a, fb) to mark pinned page a on frame b
    28→  // we use [<-mru_ghost-][<-mru-]![-mfu->][->mfu_ghost->] p=x
    29→  // to denote the 4 lists where pages closer to ! is are more fresh
    30→  // and record the mru target size as x
    31→  ArcReplacer arc_replacer(7);
    32→  // Add six frames to the replacer.
    33→  // We set frame 6 as non-evictable. These pages all go to mru list
    34→  // We now have frames [][(1,f1), (2,f2), (3,f3), (4,f4), (5,f5), p(6,f6)]![][]
    35→  arc_replacer.RecordAccess(1, 1);
    36→  arc_replacer.RecordAccess(2, 2);
    37→  arc_replacer.RecordAccess(3, 3);
    38→  arc_replacer.RecordAccess(4, 4);
    39→  arc_replacer.RecordAccess(5, 5);
    40→  arc_replacer.RecordAccess(6, 6);
    41→  arc_replacer.SetEvictable(1, true);
    42→  arc_replacer.SetEvictable(2, true);
    43→  arc_replacer.SetEvictable(3, true);
    44→  arc_replacer.SetEvictable(4, true);
    45→  arc_replacer.SetEvictable(5, true);
    46→  arc_replacer.SetEvictable(6, false);
    47→
    48→  // The size of the replacer is the number of frames that can be evicted, _not_ the total number of frames entered.
    49→  ASSERT_EQ(5, arc_replacer.Size());
    50→  // Record an access for frame 1. Now frame 1 goes into mfu list
    51→  arc_replacer.RecordAccess(1, 1);
    52→  // Now [][(2,f2), (3,f3), (4,f4), (5,f5), p(6,f6)]![(1,f1)][] p=0
    53→  //
    54→  // Now Evict three pages from the replacer.
    55→  // Since target size is still 0, mru side should be evicted
    56→  ASSERT_EQ(2, arc_replacer.Evict());
    57→  ASSERT_EQ(3, arc_replacer.Evict());
    58→  ASSERT_EQ(4, arc_replacer.Evict());
    59→  ASSERT_EQ(2, arc_replacer.Size());
    60→  // Now [(2,_), (3,_), (4,_)][(5,f5), p(6,f6)]![(1,f1)][] p=0
    61→
    62→  // Insert new page 7 on frame 2, this should NOT be a hit on ghost
    63→  // list since we've never seen page 7, this goes into mru list
    64→  arc_replacer.RecordAccess(2, 7);
    65→  arc_replacer.SetEvictable(2, true);
    66→  // Insert page 2 on frame 3, this should be a hit on mru ghost list
    67→  // since we've just evicted page 2, this goes into mfu list
    68→  // also target size should be bumped up by 1, since mru ghost has
    69→  // size 3 and mfu ghost has size 0
    70→  // starting with x is pageid on ghost list, starting with _ is pinned
    71→  arc_replacer.RecordAccess(3, 2);
    72→  arc_replacer.SetEvictable(3, true);
    73→  // Now [(3,_), (4,_)][(5,f5), p(6,f6), (7,f2)]![(2,f3), (1,f1)][] p=1
    74→  ASSERT_EQ(4, arc_replacer.Size());
    75→
    76→  // Continue to insert page 3 on frame 4 and page 4 on frame 7
    77→  arc_replacer.RecordAccess(4, 3);
    78→  arc_replacer.SetEvictable(4, true);
    79→  arc_replacer.RecordAccess(7, 4);
    80→  arc_replacer.SetEvictable(7, true);
    81→  // Now [][(5,f5), p(6,f6), (7,f2)]![(4,f7), (3,f4), (2,f3), (1,f1)][] p=3
    82→  ASSERT_EQ(6, arc_replacer.Size());
    83→
    84→  // Evict an entry, now target size is 3, we still evict from mru
    85→  ASSERT_EQ(5, arc_replacer.Evict());
    86→  // Now [(5,_)][p(6,f6), (7,f2)]![(4,f7), (3,f4), (2,f3), (1,f1)][] p=3
    87→  // Evict another entry, this time mru is smaller than target,
    88→  // mfu is victimized
    89→  ASSERT_EQ(1, arc_replacer.Evict());
    90→  // Now [(5,_)][p(6,f6), (7,f2)]![(4,f7), (3,f4), (2,f3)][(1,_)] p=3
    91→
    92→  // Make another access to page 1 on frame 5, now page 1 is back to mfu
    93→  // with a different frame, also p is adjusted down by 1/1=1
    94→  arc_replacer.RecordAccess(5, 1);
    95→  arc_replacer.SetEvictable(5, true);
    96→  // Now [(5,_)][p(6,f6), (7,f2)]![(1,f5), (4,f7), (3,f4), (2,f3)][] p=2
    97→  ASSERT_EQ(5, arc_replacer.Size());
    98→
    99→  // We evict again, this time target size is 2, we evict from mru,
   100→  // note that page 6 is pinned. Victim is page 7
   101→  // Now [(5,_), (7,_)][p(6,f6)]![(1,f5), (4,f7), (3,f4), (2,f3)][] p=2
   102→  ASSERT_EQ(2, arc_replacer.Evict());
   103→}
